content.code:
header {
  display: flex;
  width: 1818px;
  justify-content: space-between;
  align-items: center;
}

main {
  display: flex;
  width: 1048px;
  flex-direction: column;
  gap: 120px;
}

.card-wrapper {
  display: flex;
  flex-direction: column;
  gap: 32px;
}

.content-card-wrapper {
  display: flex;
  justify-content: space-between;
}

.text-card-wrapper {
  display: flex;
  width: 817px;
  flex-direction: column;
  gap: 24px;
}

.programs-section, .programms-wrapper {
  display: flex;
  flex-direction: column;
  gap: 48px;
}

.program-item {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.contact-form {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.all-inputs {
  display: flex;
  flex-direction: column;
  gap: 12px;
}
